## get color map Blues
cmap2 = plt.get_cmap('Blues')
colors  = [cmap1(i/len(gen_info)) for i in range(len(gen_info))]

    
plt.rcParams['axes.facecolor'] = "#1d1d1d"
plt.rcParams['ytick.color'] = "#e6e6e6"
plt.rcParams['xtick.color'] = "#e6e6e6"
plt.rcParams['axes.labelcolor'] = "#e6e6e6"
plt.rcParams['figure.facecolor'] = "#1d1d1d"
plt.figure(figsize=(20,6))

c_idx = 0
for i,j,k in gen_info:
    if k != 0.0 and j/k < 1.0:
        plt.plot([i,i], [0,j/k], color = "yellow", ls ="-", zorder=3)
        if j/k > 0.0:
            c_idx += 1
            plt.plot(i,j/k, zorder=3, marker = f'${j/k:1.2f}$'.format(j/k), markersize = 16, color = colors[c_idx]) ## not all percentage used, and more than non used
            index.append(i)
        else:
            plt.plot(i,j/k, marker = "o", markersize = 2, color = "white")
    else:
        if k != 0:
            plt.plot([i,i], [0,j/k], color = "magenta", lw=.5, ls ="--")
        else:
            plt.plot(i,0, marker = "o", markersize = 2, color = "white")
        # plt.plot(i,j/k, marker = "*")

overall_used = sum(list(zip(*gen_info))[1])/sum(list(zip(*gen_info))[2])+.0005 # overall generation capacity used. 

plt.axhline(overall_used, color = colors[c_idx], label="Total Capacity Used") ## total percentage used 
plt.ylabel("Percentage Used", fontsize=14)
plt.xlabel("Generator ID", fontsize=14) 
# plt.xticks(index, rotation="vertical", fontsize = 5) ## can uncomment if xticks are desired. Will only show ticks for generators which are not using all capacity
plt.yticks(sorted([i for i in np.arange(0,1.2,.2)] + [overall_used]))

## adjusting so that more ticks fit 
####
plt.gca().margins(x=0)
plt.gcf().canvas.draw()
tl = plt.gca().get_xticklabels()
maxsize = max([t.get_window_extent().width for t in tl])
m = 1.1 # inch margin
s = maxsize/plt.gcf().dpi*len(index)+2*m
margin = m/plt.gcf().get_size_inches()[0]
plt.gcf().subplots_adjust(left=margin, right=1.-margin)
plt.gcf().set_size_inches(s, plt.gcf().get_size_inches()[1])
